// ============================================================
// SECURITY TAG MATCHING (fuzzy 5-digit)
// ============================================================
function matchSecurityTag(input, lotNumber) {
  const cleanInput = input.replace(/\D/g, "");
  const cleanLot = lotNumber.replace(/\D/g, "");
  if (cleanInput.length < 5) return false;
  if (cleanInput === cleanLot) return true;
  if ("0" + cleanInput === cleanLot) return true;
  if (cleanInput === "0" + cleanLot) return true;
  if (cleanInput.length >= 5 && cleanLot.length >= 5) {
    return cleanInput.slice(-5) === cleanLot.slice(-5);
  }
  return false;
}

